import React, { useEffect, useState } from "react";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";
import axios from 'axios'
import { useNavigate } from 'react-router-dom'

ChartJS.register(ArcElement, Tooltip, Legend);

const Dashboard = () => {
  const [emotionTotals, setEmotionTotals] = useState({});
  const [store, setStore] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchAndAnalyze = async () => {
      try {
        const response = await axios.get('/api/journal/getAllJournals/687e7cd167ec0a24dc89bc80', {
          headers: {
            'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzMTg0NzgxfQ.BEMGmocSIlMu7U6po-i3K2cQXspC2uZz1VAn3fPYHek"
          }
        });
        const journals = response.data.journals || [];
        setStore(journals);

        const totals = {};
        const counts = {};

        journals.forEach((entry) => {
          if (entry.analyzed && entry.analysis) {
            const analysis = parseAnalysisString(entry.analysis);
            Object.entries(analysis).forEach(([emotion, score]) => {
              totals[emotion] = (totals[emotion] ?? 0) + score;
              counts[emotion] = (counts[emotion] ?? 0) + 1;
            });
          }
        });

        const cumulativePercentage = {};
        for (const emotion in totals) {
          cumulativePercentage[emotion] = totals[emotion] / counts[emotion];
        }

        setEmotionTotals(cumulativePercentage);
      } catch (error) {
        console.error("Error fetching journals:", error);
      }
    };

    fetchAndAnalyze();
  }, []);

  const parseAnalysisString = (str) => {
    const result = {};
    const cleaned = str.replace(/^Top Emotions:\s*/i, "");
    const parts = cleaned.split(",");
    parts.forEach((part) => {
      const [name, p] = part.trim().split(" ")
      if (!name || !p) return;
      const percent = p.replace("%)", "").replace("(", "");
      if (name && percent) {
        result[name.trim().toLowerCase()] = parseFloat(percent);
      }
    });

    return result;
  };


  const generatePieData = (emotion, percent) => ({
    labels: [emotion, "Other"],
    datasets: [
      {
        label: `${emotion} Chart`,
        data: [percent, 100 - percent],
        backgroundColor: [
          "#7e5f40",
          "#d6b98c"
        ],
        hoverBackgroundColor: [
          "#7e5f40",
          "#d6b98c"
        ],
        borderColor: "#7e5f40",
        borderWidth: 1
      }
    ]
  });
  const options = {
    plugins: {
      legend: {
        labels: {
          color: "#7e5f40"
        }
      },
      tooltip: {
        titleColor: "#d6b98c",
        bodyColor: "#d6b98c"
      }
    }
  };

  return (
    <>
      <div className='navbar'>
        <button onClick={() => navigate('/home')}>
          <img src='/assets/home.png' />
        </button>
      </div>
      <div className="dashboard-page">
        <h1>Emotion Overview</h1>
        {Object.keys(emotionTotals).length === 0 ? (
          <p>No analyzed data found.</p>
        ) : (
          <div className="emotion-charts">
            {Object.entries(emotionTotals).map(([emotion, percent]) => (
              <div className="emotion-chart" key={emotion}>
                <h3>{emotion.charAt(0).toUpperCase() + emotion.slice(1)} ({percent.toFixed(1)}%)</h3>
                <Pie data={generatePieData(emotion, percent)} options={options} />
              </div>
            ))}
          </div>
        )}
        <Stylesheet />
      </div>
    </>
  );
};

const Stylesheet = () => {
  return <style>{`
        .navbar{
          display:flex;
          padding: 2rem;
          justify-content:flex-left;
        }

        button{
           background:none;
           border:none;
        }

        .dashboard-page {
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        h1 {
          font-size: 2.2rem;
          margin-bottom: 2rem;
          color: var(--secondary-text);
        }

        .emotion-charts {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          gap: 1.5rem;
          color: var(--secondary-text);
          width: 100%;
          max-width: 920px;
        }

        .emotion-chart {
          width: 250px;
          padding: 1rem;
          border-radius: 10px;
          text-align: center;
        }
        .emotion-chart h3 {
          margin-bottom: 0.5rem;
        }
      `}</style>
}

export default Dashboard;
